defmodule WebhookProxyWeb.ProxyController do
  use WebhookProxyWeb, :controller

  @allowed_hosts [
    "api.example.com",
    "webhooks.example.com",
    "external-service.com"
  ]

  @private_ip_ranges [
    {{127, 0, 0, 0}, {127, 255, 255, 255}},
    {{10, 0, 0, 0}, {10, 255, 255, 255}},
    {{172, 16, 0, 0}, {172, 31, 255, 255}},
    {{192, 168, 0, 0}, {192, 168, 255, 255}},
    {{169, 254, 0, 0}, {169, 254, 255, 255}},
    {{224, 0, 0, 0}, {239, 255, 255, 255}},
    {{0, 0, 0, 0}, {0, 255, 255, 255}},
    {{100, 64, 0, 0}, {100, 127, 255, 255}},
    {{192, 0, 0, 0}, {192, 0, 0, 255}},
    {{192, 0, 2, 0}, {192, 0, 2, 255}},
    {{198, 51, 100, 0}, {198, 51, 100, 255}},
    {{203, 0, 113, 0}, {203, 0, 113, 255}},
    {{240, 0, 0, 0}, {255, 255, 255, 255}}
  ]

  def fetch(conn, %{"url" => url}) do
    with {:ok, validated_url} <- validate_url(url),
         {:ok, host} <- extract_host(validated_url),
         :ok <- check_allowed_host(host),
         :ok <- check_ip_address(host),
         {:ok, response} <- fetch_with_redirect_protection(validated_url) do
      json(conn, %{
        status: "success",
        content: response.body,
        headers: Enum.into(response.headers, %{}),
        status_code: response.status_code
      })
    else
      {:error, :invalid_url} ->
        conn
        |> put_status(:bad_request)
        |> json(%{error: "Invalid URL format"})

      {:error, :host_not_allowed} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Host not in allowlist"})

      {:error, :private_ip_blocked} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Access to private IP ranges is blocked"})

      {:error, :redirect_blocked} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Redirect to blocked destination"})

      {:error, reason} ->
        conn
        |> put_status(:bad_gateway)
        |> json(%{error: "Failed to fetch content: #{inspect(reason)}"})
    end
  end

  def fetch(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{error: "Missing required parameter: url"})
  end

  defp validate_url(url) when is_binary(url) do
    uri = URI.parse(url)

    case uri do
      %URI{scheme: scheme, host: host} when scheme in ["http", "https"] and is_binary(host) ->
        {:ok, url}

      _ ->
        {:error, :invalid_url}
    end
  end

  defp validate_url(_), do: {:error, :invalid_url}

  defp extract_host(url) do
    case URI.parse(url) do
      %URI{host: host} when is_binary(host) -> {:ok, host}
      _ -> {:error, :invalid_url}
    end
  end

  defp check_allowed_host(host) do
    if host in @allowed_hosts do
      :ok
    else
      {:error, :host_not_allowed}
    end
  end

  defp check_ip_address(host) do
    case resolve_host(host) do
      {:ok, ip_addresses} ->
        if Enum.all?(ip_addresses, &valid_ip?/1) do
          :ok
        else
          {:error, :private_ip_blocked}
        end

      {:error, _} ->
        {:error, :dns_resolution_failed}
    end
  end

  defp resolve_host(host) do
    charlist_host = String.to_charlist(host)

    case :inet.getaddrs(charlist_host, :inet) do
      {:ok, addresses} when length(addresses) > 0 -> {:ok, addresses}
      {:ok, []} -> {:error, :no_addresses}
      {:error, reason} -> {:error, reason}
    end
  end

  defp valid_ip?(ip_tuple) do
    not is_private_ip?(ip_tuple)
  end

  defp is_private_ip?(ip_tuple) do
    Enum.any?(@private_ip_ranges, fn {range_start, range_end} ->
      ip_in_range?(ip_tuple, range_start, range_end)
    end)
  end

  defp ip_in_range?(ip, range_start, range_end) do
    ip_to_int(ip) >= ip_to_int(range_start) and ip_to_int(ip) <= ip_to_int(range_end)
  end

  defp ip_to_int({a, b, c, d}) do
    a * 256 * 256 * 256 + b * 256 * 256 + c * 256 + d
  end

  defp fetch_with_redirect_protection(url) do
    options = [
      follow_redirect: false,
      timeout: 10_000,
      recv_timeout: 10_000
    ]

    case HTTPoison.get(url, [], options) do
      {:ok, %HTTPoison.Response{status_code: status_code} = response}
      when status_code in 300..399 ->
        handle_redirect(response)

      {:ok, response} ->
        {:ok, response}

      {:error, reason} ->
        {:error, reason}
    end
  end

  defp handle_redirect(%HTTPoison.Response{headers: headers}) do
    case List.keyfind(headers, "Location", 0) do
      {"Location", redirect_url} ->
        with {:ok, validated_url} <- validate_url(redirect_url),
             {:ok, host} <- extract_host(validated_url),
             :ok <- check_allowed_host(host),
             :ok <- check_ip_address(host) do
          {:error, :redirect_blocked}
        else
          _ -> {:error, :redirect_blocked}
        end

      nil ->
        {:error, :redirect_without_location}
    end
  end
end